    <script>
      (function () {
        function getCurrentMessageContent() {
          const _getChatMessages = window.getChatMessages || (window.parent && window.parent.getChatMessages);
          const _getCurrentMessageId =
            window.getCurrentMessageId || (window.parent && window.parent.getCurrentMessageId);

          if (typeof _getChatMessages === 'function' && typeof _getCurrentMessageId === 'function') {
            try {
              const msgId = _getCurrentMessageId();
              const msgs = _getChatMessages(msgId);
              if (msgs && msgs.length > 0) {
                return msgs[0].message;
              }
            } catch (e) {
              console.error('Error getting message content:', e);
            }
          }
          return null;
        }

        function parseChoices(content) {
          if (!content) return [];

          const blockRegex = /<choice>([\s\S]*?)<\/choice>/i;
          const match = content.match(blockRegex);
          if (!match) return [];

          const innerText = match[1];
          const lines = innerText.split('\n');
          const choices = [];

          lines.forEach(line => {
            const lineMatch = line.match(/^\s*(.*?)\s*-\s*(.*?)\s*$/);
            if (lineMatch) {
              choices.push({
                text: lineMatch[1].trim(),
                desc: lineMatch[2].trim(),
              });
            }
          });
          return choices;
        }

        function render() {
          const container = document.getElementById('choice-list-container');
          if (!container) return;

          const content = getCurrentMessageContent();
          if (!content) {
            container.innerHTML = '<div style="color: #94a3b8; text-align: center;">无法获取消息内容</div>';
            return;
          }

          const choices = parseChoices(content);
          if (choices.length === 0) {
            container.innerHTML = '<div style="color: #94a3b8; text-align: center;">解析失败或无选项</div>';
            return;
          }

          let html = '';
          choices.forEach((choice, index) => {
            let cleanText = choice.text.replace(/^\d+[\.\、\s]*/, '').trim();
            const sendText = cleanText + ' ' + choice.desc;
            const safeText = choice.text.replace(/"/g, '"').replace(/</g, '<').replace(/>/g, '>');
            const safeDesc = choice.desc.replace(/"/g, '"').replace(/</g, '<').replace(/>/g, '>');
            const safeSendText = sendText.replace(/"/g, '"').replace(/</g, '<').replace(/>/g, '>');
            html += `
                  <div class="choice-item" onclick="selectChoice(this)" data-send-text="${safeSendText}">
                    <strong class="choice-text">${safeText}</strong>
                    <span style="color: #94a3b8; font-size: 0.9em;"> - ${safeDesc}</span>
                  </div>
                `;
          });
          container.innerHTML = html;
        }

        window.selectChoice = function (element) {
          const text = element.getAttribute('data-send-text');
          if (!text) return;

          const _triggerSlash = window.triggerSlash || (window.parent && window.parent.triggerSlash);

          if (typeof _triggerSlash === 'function') {
            _triggerSlash('/setinput ' + text);
          } else {
            console.warn('triggerSlash not found');
          }
        };

        setTimeout(render, 100);
      })();
    </script>
